import { Item } from './js/Item';
import { Button } from './js/Button';
import './App.css';
import React from 'react';
import { TodoList } from './js/TodoList';
import { Header } from './js/Header';
import { Search } from './js/Search';

function App() {
  const API_URL = 'http://localhost:8080/ReackService/Service.php';

  const [tasks_m, setTasks] = React.useState([]);
  const [loading, setLoading] = React.useState(true);
  const [searchValue, setSearchValue] = React.useState('');

  const loadTasks = async () => {
    try {
      setLoading(true);

      const response = await fetch(API_URL);
      const data = await response.json();

      setTasks(Array.isArray(data) ? data : []);
    } catch (error) {
      console.error('Error al consumir el servicio:', error);
    } finally {
      setLoading(false);
    }
  };

  React.useEffect(() => {
    loadTasks();
  }, []);

  const numberTasksCompleted = tasks_m.filter(task => task.completed).length;
  const totalTasks = tasks_m.length;

  const searchTodos = tasks_m.filter((task) => {
    const searchText = searchValue.toLowerCase();
    return task.text.toLowerCase().includes(searchText);
  });

  const completedTasks = async (id) => {
    try {
      const response = await fetch(API_URL, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          id: id
        })
      });

      const data = await response.json();
      setTasks(data);
    } catch (error) {
      console.error('Error al completar tarea:', error);
    }
  };

  const deleteTasks = async (id) => {
    try {
      const response = await fetch(API_URL, {
        method: 'DELETE',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          id: id
        })
      });

      const data = await response.json();
      setTasks(data);
    } catch (error) {
      console.error('Error al eliminar tarea:', error);
    }
  };

  const addTask = async (text) => {
    try {
      const response = await fetch(API_URL, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          text: text
        })
      });

      const newTask = await response.json();

      setTasks([...tasks_m, newTask]);
    } catch (error) {
      console.error('Error al agregar tarea:', error);
    }
  };

  return (
    <React.Fragment>

      <Header completed={numberTasksCompleted} total={totalTasks} />

      <Search searchValue={searchValue} setSearchValue={setSearchValue} />

      <TodoList>
        {loading && <p>Cargando tareas...</p>}

        {!loading && searchTodos.map(task => (
          <Item
            key={task.id}
            text={task.text}
            completed={task.completed}
            onCompleted={() => completedTasks(task.id)}
            onDelete={() => deleteTasks(task.id)}
          />
        ))}
      </TodoList>

      <Button addTask={addTask} />

    </React.Fragment>
  );
}

export default App;
